import{_ as a,a as t,b as n}from"./chunks/配置渠道内容.HzNkdrom.js";import{_ as i,o as l,c as o,a2 as d}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"Een GitLab Packages-kanaal toevoegen","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/upload/gitlab-packages.md","filePath":"nl-NL/upload/gitlab-packages.md","lastUpdated":1781962217000}'),s={name:"nl-NL/upload/gitlab-packages.md"};function r(c,e,p,h,g,b){return l(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="een-gitlab-packages-kanaal-toevoegen" tabindex="-1">Een GitLab Packages-kanaal toevoegen <a class="header-anchor" href="#een-gitlab-packages-kanaal-toevoegen" aria-label="Permalink to &quot;Een GitLab Packages-kanaal toevoegen&quot;">​</a></h1><h2 id="wat-je-vooraf-nodig-hebt" tabindex="-1">Wat je vooraf nodig hebt <a class="header-anchor" href="#wat-je-vooraf-nodig-hebt" aria-label="Permalink to &quot;Wat je vooraf nodig hebt&quot;">​</a></h2><p>Je hebt maar drie dingen nodig:</p><table tabindex="0"><thead><tr><th>Vereiste</th><th>Doel</th></tr></thead><tbody><tr><td>GitLab-account</td><td>Voor het maken van een access token en als eigenaar van het project.</td></tr><tr><td>GitLab Personal Access Token</td><td>Hiermee kan ImgBed de GitLab API gebruiken, projecten maken en bestanden uploaden naar Generic Packages.</td></tr><tr><td>Projectnaam</td><td>Je kunt alleen de projectnaam invullen, bijvoorbeeld <code>imgbed</code>.</td></tr></tbody></table><h2 id="instellen" tabindex="-1">Instellen <a class="header-anchor" href="#instellen" aria-label="Permalink to &quot;Instellen&quot;">​</a></h2><h3 id="stap-1-log-in-bij-gitlab-en-maak-een-access-token" tabindex="-1">Stap 1: Log in bij GitLab en maak een Access Token <a class="header-anchor" href="#stap-1-log-in-bij-gitlab-en-maak-een-access-token" aria-label="Permalink to &quot;Stap 1: Log in bij GitLab en maak een Access Token&quot;">​</a></h3><ol><li>Log in bij GitLab.</li><li>Klik rechtsboven op je avatar en open <code>Preferences</code>.</li><li>Open <code>Access Tokens</code> in de linkerzijbalk.</li><li>Geef het token een herkenbare naam.</li><li>Kies een verloopdatum die past bij je beheerplanning.</li><li>Selecteer de scope <code>api</code>.</li><li>Kopieer en bewaar het token direct nadat het is aangemaakt.</li></ol><p><img src="'+a+'" alt="Legacy-token maken" loading="lazy"></p><p><img src="'+t+'" alt="Tokenrechten selecteren" loading="lazy"></p><h2 id="stap-2-vul-het-gitlab-packages-kanaal-in-imgbed-in" tabindex="-1">Stap 2: Vul het GitLab Packages-kanaal in ImgBed in <a class="header-anchor" href="#stap-2-vul-het-gitlab-packages-kanaal-in-imgbed-in" aria-label="Permalink to &quot;Stap 2: Vul het GitLab Packages-kanaal in ImgBed in&quot;">​</a></h2><p>Nadat je in Uploadinstellingen <code>GitLab Packages</code> hebt gekozen, vul je in:</p><table tabindex="0"><thead><tr><th>UI-veld</th><th>Wat je invult</th></tr></thead><tbody><tr><td>Kanaalnaam</td><td>Een naam naar keuze, bijvoorbeeld <code>GitLabPrimary</code>.</td></tr><tr><td>Access Token</td><td>Het GitLab Personal Access Token dat je net hebt gemaakt.</td></tr><tr><td>Projectnaam</td><td>Een korte projectnaam zoals <code>imgbed</code>, of een volledig pad zoals <code>username/imgbed</code>.</td></tr><tr><td>Privérepository</td><td>Zet aan of uit naar behoefte.</td></tr><tr><td>Opmerking</td><td>Optioneel, bijvoorbeeld <code>Primary upload channel</code>.</td></tr></tbody></table><p><img src="'+n+`" alt="Kanaal configureren" loading="lazy"></p><h2 id="stap-3-sla-het-kanaal-op" tabindex="-1">Stap 3: Sla het kanaal op <a class="header-anchor" href="#stap-3-sla-het-kanaal-op" aria-label="Permalink to &quot;Stap 3: Sla het kanaal op&quot;">​</a></h2><p>Klik na het invullen op Opslaan.</p><p>Het systeem handelt deze details af:</p><table tabindex="0"><thead><tr><th>Systeemgedrag</th><th>Beschrijving</th></tr></thead><tbody><tr><td>Korte projectnaam</td><td>ImgBed herkent het huidige GitLab-account en vult dit aan tot een volledig projectpad.</td></tr><tr><td>Volledig projectpad</td><td>ImgBed gebruikt <code>username/project</code> exact zoals ingevoerd.</td></tr><tr><td>Projectcontrole</td><td>Gebruik je het pad van je huidige persoonlijke account, dan maakt ImgBed het project automatisch aan als het niet bestaat. Vul je handmatig een volledig pad in, dan gebruikt ImgBed dat pad direct.</td></tr><tr><td>Openbaar/privé</td><td>De zichtbaarheid van het project wordt gesynchroniseerd met de huidige schakelaar.</td></tr></tbody></table><h2 id="snelle-checklist" tabindex="-1">Snelle checklist <a class="header-anchor" href="#snelle-checklist" aria-label="Permalink to &quot;Snelle checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Log in bij GitLab</span></span>
<span class="line"><span>-&gt; Maak een Access Token</span></span>
<span class="line"><span>-&gt; Selecteer alleen de api-scope</span></span>
<span class="line"><span>-&gt; Ga terug naar ImgBed en vul token en projectnaam in</span></span>
<span class="line"><span>-&gt; Sla op</span></span>
<span class="line"><span>-&gt; Als alleen een projectnaam is ingevuld, voegt ImgBed automatisch de huidige gebruikersnaam toe</span></span>
<span class="line"><span>-&gt; Als username/project is ingevuld, gebruikt ImgBed dit zoals het is</span></span>
<span class="line"><span>-&gt; Upload een testafbeelding</span></span></code></pre></div>`,19)])])}const v=i(s,[["render",r]]);export{u as __pageData,v as default};
